VALUES
  ('fire-eq-tech-moex-02790', 'fire-eq-tech', 'fire-eq-tech-moex-098-1776de84', 'sub-fire-eq-tech-06', NULL, 'single_choice', '依據各類場所消防安全設備設置標準之規定，下列有關泡沫滅火設備之敘述，何者正確？', '["固定式泡沫滅火設備，配置強制風機式高發泡放出口膨脹比可達1000以下", "固定式泡沫滅火設備之泡沫放出口，如果膨脹比在1000以下，宜採用空氣吸引式高發泡放出口", "使用水成膜泡沫液時，樓地板面積每平方公尺之放射量為每分鐘6.5公升以上", "泡水噴頭放射量不得小於每分鐘130公升"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "2ed3c96ede36", "answer_pdf_sha1": "6d38eff788b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水災與化學系統消防安全設備概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02791', 'fire-eq-tech', 'fire-eq-tech-moex-098-1776de84', 'sub-fire-eq-tech-06', NULL, 'single_choice', '當操作泡沫瞄子時，若送水壓力過低，則藥劑吸入量太少，泡沫產生效果低，恐無法有效滅火，瞄子 出水口壓力必須保持在下列何者之間？', '["1.7 kgf/cm2至2.5 kgf/cm2", "3.5 kgf/cm2至4.9 kgf/cm2", "5.0 kgf/cm2至6.3 kgf/cm2", "6.5 kgf/cm2至8.0 kgf/cm2"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "2ed3c96ede36", "answer_pdf_sha1": "6d38eff788b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水災與化學系統消防安全設備概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02792', 'fire-eq-tech', 'fire-eq-tech-moex-098-1776de84', 'sub-fire-eq-tech-06', NULL, 'single_choice', '30 m×30 m×6 m（高）之汽車修護廠，防護對象物之尺寸為10 m×10 m×3 m（高），若使用3%水成膜 泡沫原液，及膨脹比為350，且採全區放射方式，則其冠泡體積為多少？', '["2600 m3", "2850 m3", "3150 m3", "3500 m3"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "2ed3c96ede36", "answer_pdf_sha1": "6d38eff788b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水災與化學系統消防安全設備概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02793', 'fire-eq-tech', 'fire-eq-tech-moex-098-1776de84', 'sub-fire-eq-tech-06', NULL, 'single_choice', '停車空間泡沫滅火設備進行放射試驗時，其發泡倍率應達多少倍以上？', '["二倍以上", "三倍以上", "四倍以上", "五倍以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "2ed3c96ede36", "answer_pdf_sha1": "6d38eff788b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水災與化學系統消防安全設備概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02794', 'fire-eq-tech', 'fire-eq-tech-moex-098-1776de84', 'sub-fire-eq-tech-06', NULL, 'single_choice', '依據各類場所消防安全設備設置標準之規定，消防專用蓄水池之設置，下列何者錯誤？', '["有進水管投入後，能有效抽取所需水量之構造", "應設於消防車能接近至其5公尺範圍內，易於抽取處", "任一消防專用蓄水池至建築物各部分之水平距離不得超過100公尺", "其有效水量在20立方公尺以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "2ed3c96ede36", "answer_pdf_sha1": "6d38eff788b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水災與化學系統消防安全設備概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02795', 'fire-eq-tech', 'fire-eq-tech-moex-098-1776de84', 'sub-fire-eq-tech-06', NULL, 'single_choice', '連結送水管之中繼幫浦放水測試時，應從送水口以送水設計壓力送水，並以口徑二十一公厘瞄子在最頂層 測試，其放水壓力不得小於每平方公分多少公斤？且放水量不得小於每分鐘多少公升？', '["每平方公分八公斤；每分鐘六百公升", "每平方公分六公斤；每分鐘六百公升", "每平方公分八公斤；每分鐘八百公升", "每平方公分六公斤；每分鐘八百公升"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "2ed3c96ede36", "answer_pdf_sha1": "6d38eff788b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水災與化學系統消防安全設備概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02796', 'fire-eq-tech', 'fire-eq-tech-moex-098-1776de84', 'sub-fire-eq-tech-06', NULL, 'single_choice', '加壓送水裝置中消防幫浦動力來源採用電動機啟動方式，下列敘述何者錯誤？', '["電動機輸出功率11 KW以上者可採用直接啟動法", "補償器啟動法指電動機與電源之間接有單繞變壓器", "星角（Y一△）啟動法為電動機定子線圈形成Y結線目的先將減少啟動電流，待加速後再切換為△形 結線進入運轉", "電動機與電源之間加入啟動電抗器以產生壓降稱為電抗器啟動法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "2ed3c96ede36", "answer_pdf_sha1": "6d38eff788b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水災與化學系統消防安全設備概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02797', 'fire-eq-tech', 'fire-eq-tech-moex-098-1776de84', 'sub-fire-eq-tech-06', NULL, 'single_choice', '泡沫滅火設備竣工查驗作業規定，進行綜合試驗低發泡放射試驗，下列何者正確？', '["泡沫稀釋濃度6%型者應在6%~7%範圍內", "發泡倍率10倍以上", "25%還液時間水成膜泡沫應在60秒以上", "放射區域就預設放射壓力最高處實施"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "2ed3c96ede36", "answer_pdf_sha1": "6d38eff788b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水災與化學系統消防安全設備概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
