  ('fire-eq-tech-moex-02799', 'fire-eq-tech', 'fire-eq-tech-moex-098-1776de84', 'sub-fire-eq-tech-06', NULL, 'single_choice', '二氧化碳滅火設備在防護空間單位體積所需之藥劑量為0.9 kg/m3時，其二氧化碳之濃度為多少？', '["39%", "35%", "33%", "29%"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "2ed3c96ede36", "answer_pdf_sha1": "6d38eff788b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水災與化學系統消防安全設備概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
